   362	func detectGoModuleConfig(startDir string) (modulePath, langVersion string) {
   363		dir, err := filepath.Abs(startDir)
   364		if err != nil {
   365			dir = startDir
   366		}
   367	
   368		for dir != "" {
   369			data, err := os.ReadFile(filepath.Join(dir, "go.mod"))
   370			if err == nil {
   371				return parseGoModMetadata(data)
   372			}
   373	
   374			parent := filepath.Dir(dir)
   375			if parent == dir {
   376				break
   377			}
   378			dir = parent
   379		}
   380	
   381		return "", ""
   382	}
