   384	func parseGoModMetadata(data []byte) (modulePath, langVersion string) {
   385		for line := range strings.SplitSeq(string(data), "\n") {
   386			fields := strings.Fields(strings.TrimSpace(line))
   387			if len(fields) < 2 {
   388				continue
   389			}
   390	
   391			switch fields[0] {
   392			case "module":
   393				if modulePath == "" {
   394					modulePath = strings.Trim(fields[1], "\"")
   395				}
   396			case "go":
   397				if langVersion == "" {
   398					langVersion = "go" + fields[1]
   399				}
   400			}
   401	
   402			if modulePath != "" && langVersion != "" {
   403				break
   404			}
   405		}
   406	
   407		return modulePath, langVersion
   408	}
